-- ============================================================================
-- 014_conversation_layer.sql
-- ============================================================================
-- Migration 014 — AI Reasoning Memory + Conversation Threads (File 23).

-- ── decision_traces ──────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS decision_traces (
    id               INTEGER PRIMARY KEY AUTOINCREMENT,
    pipeline_run_id  INTEGER,
    step_index       INTEGER,
    module_name      TEXT NOT NULL DEFAULT '',
    lead_id          INTEGER,
    contact_id       INTEGER,
    decision_type    TEXT NOT NULL
        CHECK(decision_type IN ('score','draft','quality','send','reply','tuning','thread')),
    input_snapshot   TEXT,          -- JSON
    rationale        TEXT,
    model_name       TEXT,
    tokens_in        INTEGER,
    tokens_out       INTEGER,
    confidence       REAL,
    created_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%S','now')),
    FOREIGN KEY (pipeline_run_id) REFERENCES pipeline_runs(id) ON DELETE SET NULL,
    FOREIGN KEY (lead_id)        REFERENCES lead_candidates(id) ON DELETE SET NULL,
    FOREIGN KEY (contact_id)     REFERENCES contacts(id)        ON DELETE SET NULL
);

CREATE INDEX IF NOT EXISTS idx_dt_run      ON decision_traces(pipeline_run_id);
CREATE INDEX IF NOT EXISTS idx_dt_lead     ON decision_traces(lead_id);
CREATE INDEX IF NOT EXISTS idx_dt_contact  ON decision_traces(contact_id);
CREATE INDEX IF NOT EXISTS idx_dt_type     ON decision_traces(decision_type);
CREATE INDEX IF NOT EXISTS idx_dt_created  ON decision_traces(created_at DESC);

-- ── lead_threads ─────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS lead_threads (
    id               INTEGER PRIMARY KEY AUTOINCREMENT,
    project_id       INTEGER NOT NULL,
    icp_id           INTEGER,
    lead_id          INTEGER,
    contact_id       INTEGER,
    subject          TEXT,
    status           TEXT NOT NULL DEFAULT 'open'
        CHECK(status IN ('open','awaiting_reply','replied','closed','bounced')),
    last_message_at  TEXT,
    last_direction   TEXT CHECK(last_direction IN ('out','in',NULL)),
    message_count    INTEGER NOT NULL DEFAULT 0,
    created_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%S','now')),
    updated_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%S','now')),
    FOREIGN KEY (project_id) REFERENCES projects(id)        ON DELETE CASCADE,
    FOREIGN KEY (icp_id)     REFERENCES icps(id)            ON DELETE SET NULL,
    FOREIGN KEY (lead_id)    REFERENCES lead_candidates(id) ON DELETE SET NULL,
    FOREIGN KEY (contact_id) REFERENCES contacts(id)        ON DELETE SET NULL
);

CREATE INDEX IF NOT EXISTS idx_lt_project   ON lead_threads(project_id);
CREATE INDEX IF NOT EXISTS idx_lt_lead      ON lead_threads(lead_id);
CREATE INDEX IF NOT EXISTS idx_lt_contact   ON lead_threads(contact_id);
CREATE INDEX IF NOT EXISTS idx_lt_status    ON lead_threads(status);
CREATE INDEX IF NOT EXISTS idx_lt_last_msg  ON lead_threads(last_message_at DESC);

-- ── lead_thread_messages ─────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS lead_thread_messages (
    id                  INTEGER PRIMARY KEY AUTOINCREMENT,
    thread_id           INTEGER NOT NULL,
    direction           TEXT NOT NULL CHECK(direction IN ('out','in')),
    source              TEXT NOT NULL DEFAULT 'manual'
        CHECK(source IN ('outreach_send','outreach_reply','manual','reply_draft')),
    external_id         TEXT,
    send_id             INTEGER,
    reply_id            INTEGER,
    draft_id            INTEGER,
    subject             TEXT,
    body_text           TEXT,
    body_html           TEXT,
    sent_at             TEXT,
    received_at         TEXT,
    headers             TEXT,           -- JSON
    attachments         TEXT,           -- JSON
    raw_data            TEXT,           -- JSON
    decision_trace_id   INTEGER,
    created_at          TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%S','now')),
    FOREIGN KEY (thread_id)          REFERENCES lead_threads(id)          ON DELETE CASCADE,
    FOREIGN KEY (send_id)            REFERENCES outreach_sends(id)        ON DELETE SET NULL,
    FOREIGN KEY (reply_id)           REFERENCES outreach_replies(id)      ON DELETE SET NULL,
    FOREIGN KEY (draft_id)           REFERENCES outreach_messages(id)     ON DELETE SET NULL,
    FOREIGN KEY (decision_trace_id)  REFERENCES decision_traces(id)       ON DELETE SET NULL
);

CREATE INDEX IF NOT EXISTS idx_ltm_thread     ON lead_thread_messages(thread_id);
CREATE INDEX IF NOT EXISTS idx_ltm_send       ON lead_thread_messages(send_id);
CREATE INDEX IF NOT EXISTS idx_ltm_reply      ON lead_thread_messages(reply_id);
CREATE INDEX IF NOT EXISTS idx_ltm_direction  ON lead_thread_messages(thread_id, direction);

-- Bump schema version
UPDATE schema_meta SET value = '14' WHERE key = 'version';

-- ============================================================================
-- 015_auth.sql
-- ============================================================================
-- Migration 015 — Auth layer (File 24).
-- users:           credentials + role
-- project_members: per-project access (owner|admin|member|viewer)
-- audit_log:       structured request/event log (optional sink)

CREATE TABLE IF NOT EXISTS users (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    email TEXT NOT NULL UNIQUE,
    password_hash TEXT NOT NULL,
    full_name TEXT,
    role TEXT NOT NULL DEFAULT 'user' CHECK (role IN ('admin', 'user')),
    is_active INTEGER NOT NULL DEFAULT 1,
    last_login_at TEXT,
    created_at TEXT DEFAULT CURRENT_TIMESTAMP,
    updated_at TEXT DEFAULT CURRENT_TIMESTAMP
);

CREATE INDEX IF NOT EXISTS idx_users_email ON users(email);

CREATE TABLE IF NOT EXISTS project_members (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    project_id INTEGER NOT NULL,
    user_id INTEGER NOT NULL,
    role TEXT NOT NULL DEFAULT 'member' CHECK (role IN ('owner', 'admin', 'member', 'viewer')),
    created_at TEXT DEFAULT CURRENT_TIMESTAMP,
    updated_at TEXT DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (project_id) REFERENCES projects(id) ON DELETE CASCADE,
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
    UNIQUE (project_id, user_id)
);

CREATE INDEX IF NOT EXISTS idx_project_members_user ON project_members(user_id);
CREATE INDEX IF NOT EXISTS idx_project_members_project ON project_members(project_id);

CREATE TABLE IF NOT EXISTS audit_log (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id INTEGER,
    project_id INTEGER,
    action TEXT NOT NULL,
    resource TEXT,
    resource_id INTEGER,
    method TEXT,
    path TEXT,
    status_code INTEGER,
    ip_address TEXT,
    user_agent TEXT,
    metadata TEXT,
    created_at TEXT DEFAULT CURRENT_TIMESTAMP
);

CREATE INDEX IF NOT EXISTS idx_audit_user ON audit_log(user_id);
CREATE INDEX IF NOT EXISTS idx_audit_project ON audit_log(project_id);
CREATE INDEX IF NOT EXISTS idx_audit_action ON audit_log(action);
CREATE INDEX IF NOT EXISTS idx_audit_created ON audit_log(created_at);

UPDATE schema_meta SET value = '15' WHERE key = 'version';
